mapper.select:
SELECT io.id, io.order_no AS orderNo, io.supplier_id AS supplierId, io.supplier_name AS supplierName, io.total_amount AS totalAmount, io.order_status AS orderStatus, CASE WHEN EXISTS ( SELECT 1 FROM ai_recognition_record air WHERE air.doc_type = 'inbound' AND air.confirmed_order_id = io.id ) THEN 'AI' ELSE 'MANUAL' END AS sourceType, io.remark, io.created_time AS createdTime FROM inbound_order io
io.order_no LIKE CONCAT('%', #{orderNo}, '%')
AND EXISTS ( SELECT 1 FROM ai_recognition_record air WHERE air.doc_type = 'inbound' AND air.confirmed_order_id = io.id )
AND NOT EXISTS ( SELECT 1 FROM ai_recognition_record air WHERE air.doc_type = 'inbound' AND air.confirmed_order_id = io.id )
AND io.order_status = #{orderStatus}
ORDER BY io.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM inbound_order
WHERE supplier_id = #{supplierId}

mapper.update:
UPDATE inbound_order
SET order_status = #{targetStatus}
WHERE id = #{id}
  AND order_status = #{sourceStatus}

UPDATE inbound_order
SET supplier_id = #{supplierId},
    supplier_name = #{supplierName},
    total_amount = #{totalAmount},
    remark = #{remark}
WHERE id = #{id}
  AND order_status = #{sourceStatus}
